#include <iostream>
#include <string>
#include <sstream>
#include <cmath>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    friend std::ostream& operator<<(std::ostream& os, const ComplexNumber& c);

    double getReal() const { return real; }
    double getImaginary() const { return imaginary; }
};

std::ostream& operator<<(std::ostream& os, const ComplexNumber& c) {
    std::stringstream ss;
    ss << "(";

    if (c.real == 0.0 && c.imaginary == 0.0) {
        ss << "0";
    } else if (c.real == 0.0) {
        if (c.imaginary == 1.0) {
            ss << "i";
        } else if (c.imaginary == -1.0) {
            ss << "-i";
        } else {
            ss << c.imaginary << "i";
        }
    } else if (c.imaginary == 0.0) {
        ss << c.real;
    } else {
        ss << c.real;
        if (c.imaginary > 0) {
            ss << " + ";
        } else {
            ss << " - ";
        }
        if (std::abs(c.imaginary) == 1.0) {
            ss << "i";
        } else {
            ss << std::abs(c.imaginary) << "i";
        }
    }
    ss << ")";
    return os << ss.str();
}

int main() {
    ComplexNumber c1(3, 4);
    ComplexNumber c2(5, -2);
    ComplexNumber c3(0, 7);
    ComplexNumber c4(-1, 0);
    ComplexNumber c5(0, 0);
